37	extern void poll_inputs(struct processor*);
38	static void __attribute__ ((format (printf, 1, 2))) send_formatted_response(const char *format, ...);
39	
40	static int client_socket = -1;
41	static int *last_signals;
42	static const char *GENERIC_REGS[] = { "fp", "sp", "ra" };
43	
44	static int read_byte(void)
45	{
46	    uint8_t ch;
47	    if (read(client_socket, &ch, 1) < 1)
48	    {
49	        perror("read_byte: error reading from debug socket");
50	        return -1;
51	    }
52	
53	    return (int) ch;
54	}
55	
56	static int read_packet(char *request, int max_length)
57	{
58	    int ch;
59	    int packet_len;
60	
61	    // Wait for packet start
62	    do
63	    {
64	        ch = read_byte();
65	        if (ch < 0)
66	            return -1;
67	    }
68	    while (ch != '$');
69	
70	    // Read body
71	    packet_len = 0;
72	    while (true)
73	    {
74	        ch = read_byte();
75	        if (ch < 0)
76	            return -1;
77	
78	        if (ch == '#')
79	            break;
80	
81	        if (packet_len < max_length)
82	            request[packet_len++] = (char) ch;
83	    }
84	
85	    // Read checksum and discard
86	    read_byte();
87	    read_byte();
88	
89	    request[packet_len] = '\0';
90	
91	#if LOG_COMMANDS
92	    printf("GDB recv: %s\n", request);
93	#endif
94	
95	    return packet_len;
96	}
97	
98	static void send_response_packet(const char *response)
99	{
100	    uint8_t checksum;
101	    char checksum_chars[16];
102	    int i;
103	    size_t response_length = strlen(response);
104	
105	#if LOG_COMMANDS
106	    printf("GDB send: %s\n", response);
107	#endif
108	
109	    if (write(client_socket, "$", 1) < 1
110	            || write(client_socket, response, response_length) < (ssize_t) response_length
111	            || write(client_socket, "#", 1) < 1)
112	    {
113	        perror("send_response_packet: Error writing to debugger socket");
114	        exit(1);
115	    }
116	
117	    checksum = 0;
118	    for (i = 0; response[i]; i++)
119	        checksum += response[i];
120	
121	    sprintf(checksum_chars, "%02x", checksum);
122	    if (write(client_socket, checksum_chars, 2) < 2)
123	    {
124	        perror("send_response_packet: Error writing to debugger socket");
125	        exit(1);
126	    }
127	}
128	
129	static void send_formatted_response(const char *format, ...)
130	{
131	    char buf[256];
132	    va_list args;
133	    va_start(args, format);
134	    vsnprintf(buf, sizeof(buf) - 1, format, args);
135	    va_end(args);
136	    send_response_packet(buf);
137	}
