139	static void run_until_interrupt(struct processor *proc, bool enable_fb_window)
140	{
141	    while (true)
142	    {
143	        if (!execute_instructions(proc, screen_refresh_rate))
144	            break;
145	
146	        if (enable_fb_window)
147	        {
148	            update_frame_buffer(proc);
149	            poll_fb_window_event();
150	            poll_inputs(proc);
151	        }
152	
153	        // Break on error or if data is ready
154	        if (can_read_file_descriptor(client_socket))
155	            break;
156	    }
157	}
