159	static uint8_t decode_hex_byte(const char *ptr)
160	{
161	    int i;
162	    int retval = 0;
163	
164	    for (i = 0; i < 2; i++)
165	    {
166	        if (ptr[i] >= '0' && ptr[i] <= '9')
167	            retval = (retval << 4) | (ptr[i] - '0');
168	        else if (ptr[i] >= 'a' && ptr[i] <= 'f')
169	            retval = (retval << 4) | (ptr[i] - 'a' + 10);
170	        else if (ptr[i] >= 'A' && ptr[i] <= 'F')
171	            retval = (retval << 4) | (ptr[i] - 'A' + 10);
172	        else
173	            assert(0);	// Bad character
174	    }
175	
176	    return (uint8_t) retval;
177	}
