179	void remote_gdb_main_loop(struct processor *proc, bool enable_fb_window)
180	{
181	    int listen_socket;
182	    struct sockaddr_in address;
183	    socklen_t address_length;
184	    int got;
185	    char request[256];
186	    uint32_t i;
187	    bool no_ack_mode = false;
188	    int optval;
189	    char response[1024];
190	    uint32_t current_thread = 0;
191	
192	    last_signals = calloc(sizeof(int), get_total_threads(proc));
193	    for (i = 0; i < get_total_threads(proc); i++)
194	        last_signals[i] = 0;
195	
196	    listen_socket = socket(PF_INET, SOCK_STREAM, 0);
197	    if (listen_socket < 0)
198	    {
199	        perror("remote_gdb_main_loop: error setting up debug socket (socket)");
200	        return;
201	    }
202	
203	    optval = 1;
204	    if (setsockopt(listen_socket, SOL_SOCKET, SO_REUSEADDR, &optval, sizeof(optval)) < 0)
205	    {
206	        perror("remote_gdb_main_loop: error setting up debug socket (setsockopt)");
207	        return;
208	    }
209	
210	    address.sin_family = AF_INET;
211	    address.sin_port = htons(8000);
212	    address.sin_addr.s_addr = htonl(INADDR_ANY);
213	    if (bind(listen_socket, (struct sockaddr*) &address, sizeof(address)) < 0)
214	    {
215	        perror("remote_gdb_main_loop: error setting up debug socket (bind)");
216	        return;
217	    }
218	
219	    if (listen(listen_socket, 1) < 0)
220	    {
221	        perror("remote_gdb_main_loop: error setting up debug socket (listen)");
222	        return;
223	    }
224	
225	    while (true)
226	    {
227	        // Wait for a new client socket
228	        while (true)
229	        {
230	            address_length = sizeof(address);
231	            client_socket = accept(listen_socket, (struct sockaddr*) &address,
232	                                   &address_length);
233	            if (client_socket >= 0)
234	                break;
235	        }
236	
237	        no_ack_mode = false;
238	
239	        // Process commands
240	        while (true)
241	        {
242	            got = read_packet(request, sizeof(request));
243	            if (got < 0)
244	                break;
245	
246	            if (!no_ack_mode)
247	            {
248	                if (write(client_socket, "+", 1) != 1)
249	                {
250	                    perror("remote_gdb_main_loop: Error writing to debug socket");
251	                    exit(1);
252	                }
253	            }
254	
255	            switch (request[0])
256	            {
257	                // Set arguments
258	                case 'A':
259	                    // Doesn't support setting program arguments, so just silently ignore.
260	                    send_response_packet("OK");
261	                    break;
262	
263	                // Continue
264	                case 'c':
265	                case 'C':
266	                    run_until_interrupt(proc, enable_fb_window);
267	                    last_signals[current_thread] = TRAP_SIGNAL;
268	                    send_formatted_response("S%02x", last_signals[current_thread]);
269	                    break;
270	
271	                // Pick thread
272	                case 'H':
273	                {
274	                    uint32_t thid;
275	
276	                    // XXX hack: the request type (request[1] controls which
277	                    // operations this applies for. I ignore it.
278	
279	                    // Thread indices in GDB start at 1, but current_thread
280	                    // is zero based.
281	                    thid = (uint32_t) strtoul(request + 2, NULL, 16);
282	                    if (thid > get_total_threads(proc) || thid == 0)
283	                    {
284	                        send_response_packet("");
285	                        break;
286	                    }
287	
288	                    current_thread = thid - 1;
289	                    send_response_packet("OK");
290	                    break;
291	                }
292	
293	                // Kill
294	                case 'k':
295	                    return;
296	
297	                // Read/write memory
298	                case 'm':
299	                case 'M':
300	                {
301	                    char *len_ptr;
302	                    char *data_ptr;
303	                    uint32_t start;
304	                    uint32_t length;
305	                    uint32_t offset;
306	
307	                    start = (uint32_t) strtoul(request + 1, &len_ptr, 16);
308	                    length = (uint32_t) strtoul(len_ptr + 1, &data_ptr, 16);
309	                    if (request[0] == 'm')
310	                    {
311	                        // XXX May need dynamic allocation. At very least, buffer is too small.
312	                        if (length > sizeof(response) / 2)
313	                        {
314	                            printf("memory read of %u requested\n", length);
315	                            assert(0);
316	                        }
317	
318	                        // Read memory
319	                        for (offset = 0; offset < length; offset++)
320	                            sprintf(response + offset * 2, "%02x", dbg_read_memory_byte(proc, start + offset));
321	
322	                        send_response_packet(response);
323	                    }
324	                    else
325	                    {
326	                        // Write memory
327	                        data_ptr += 1;	// Skip colon
328	                        for (offset = 0; offset < length; offset++)
329	                            dbg_write_memory_byte(proc, start + offset, decode_hex_byte(data_ptr + offset * 2));
330	
331	                        send_response_packet("OK");
332	                    }
333	
334	                    break;
335	                }
336	
337	                // Read register
338	                case 'p':
339	                case 'g':
340	                {
341	                    uint32_t reg_id = (uint32_t) strtoul(request + 1, NULL, 16);
342	                    uint32_t value;
343	                    if (reg_id < 32)
344	                    {
345	                        // Scalar register
346	                        value = dbg_get_scalar_reg(proc, current_thread, reg_id);
347	                        send_formatted_response("%08x", endian_swap32(value));
348	                    }
349	                    else if (reg_id < 64)
350	                    {
351	                        // Vector register
352	                        int lane_idx;
353	                        uint32_t values[NUM_VECTOR_LANES];
354	
355	                        dbg_get_vector_reg(proc, current_thread, reg_id - 32, values);
356	                        for (lane_idx = 0; lane_idx < NUM_VECTOR_LANES; lane_idx++)
357	                        {
358	                            sprintf(response + lane_idx * 8, "%08x",
359	                                endian_swap32(values[lane_idx]));
360	                        }
361	
362	                        send_response_packet(response);
363	                    }
364	                    else if (reg_id == 64)
365	                    {
366	                        // program counter
367	                        value = dbg_get_pc(proc, current_thread);
368	                        send_formatted_response("%08x", endian_swap32(value));
369	                    }
370	                    else
371	                        send_response_packet("");
372	
373	                    break;
374	                }
375	
376	                // Write register
377	                case 'G':
378	                {
379	                    char *data_ptr;
380	                    uint32_t reg_id = (uint32_t) strtoul(request + 1, &data_ptr, 16);
381	
382	                    if (reg_id < 32)
383	                    {
384	                        // Scalar register
385	                        uint32_t reg_value = (uint32_t) strtoul(data_ptr + 1, NULL, 16);
386	                        dbg_set_scalar_reg(proc, current_thread, reg_id, endian_swap32(reg_value));
387	                        send_response_packet("OK");
388	                    }
389	                    else if (reg_id < 64)
390	                    {
391	                        // Vector register
392	                        uint32_t reg_value[NUM_VECTOR_LANES];
393	
394	                        if (parse_hex_vector(data_ptr + 1, reg_value, true) < 0)
395	                            send_response_packet("");
396	                        else
397	                        {
398	                            dbg_set_vector_reg(proc, current_thread, reg_id - 32, reg_value);
399	                            send_response_packet("OK");
400	                        }
401	                    }
402	                    else
403	                        send_response_packet("");
404	
405	                    break;
406	                }
407	
408	                // Query
409	                case 'q':
410	                    if (strcmp(request + 1, "LaunchSuccess") == 0)
411	                        send_response_packet("OK");
412	                    else if (strcmp(request + 1, "HostInfo") == 0)
413	                        send_response_packet("triple:nyuzi;endian:little;ptrsize:4");
414	                    else if (strcmp(request + 1, "ProcessInfo") == 0)
415	                        send_response_packet("pid:1");
416	                    else if (strcmp(request + 1, "fThreadInfo") == 0)
417	                    {
418	                        uint32_t num_threads = get_total_threads(proc);
419	                        int offset = 2;
420	
421	                        strcpy(response, "m1");
422	                        for (i = 2; i <= num_threads && offset < (int) sizeof(response); i++)
423	                        {
424	                            offset += snprintf(response + offset, sizeof(response)
425	                                               - (size_t) offset, ",%u", i);
426	                        }
427	
428	                        send_response_packet(response);
429	                    }
430	                    else if (strcmp(request + 1, "sThreadInfo") == 0)
431	                        send_response_packet("l");
432	                    else if (memcmp(request + 1, "ThreadStopInfo", 14) == 0)
433	                        send_formatted_response("S%02x", last_signals[current_thread]);
434	                    else if (memcmp(request + 1, "RegisterInfo", 12) == 0)
435	                    {
436	                        uint32_t reg_id = (uint32_t) strtoul(request + 13, NULL, 16);
437	                        if (reg_id < 32 || reg_id == 64)
438	                        {
439	                            sprintf(response, "name:s%u;bitsize:32;encoding:uint;format:hex;set:General Purpose Scalar Registers;gcc:%u;dwarf:%u;",
440	                                    reg_id, reg_id, reg_id);
441	
442	                            if (reg_id == 64)
443	                                sprintf(response + strlen(response), "generic:pc;");
444	                            else if (reg_id >= 29)
445	                                sprintf(response + strlen(response), "generic:%s;", GENERIC_REGS[reg_id - 29]);
446	
447	                            send_response_packet(response);
448	                        }
449	                        else if (reg_id < 64)
450	                        {
451	                            send_formatted_response("name:v%d;bitsize:512;encoding:uint;format:vector-uint32;set:General Purpose Vector Registers;gcc:%d;dwarf:%d;",
452	                                                    reg_id - 32, reg_id, reg_id);
453	                        }
454	                        else
455	                            send_response_packet("");
456	
457	                    }
458	                    else if (strcmp(request + 1, "C") == 0)
459	                        send_formatted_response("QC%02x", current_thread + 1);
460	                    else
461	                        send_response_packet("");	// Not supported
462	
463	                    break;
464	
465	                // Set Value
466	                case 'Q':
467	                    if (strcmp(request + 1, "StartNoAckMode") == 0)
468	                    {
469	                        no_ack_mode = true;
470	                        send_response_packet("OK");
471	                    }
472	                    else
473	                        send_response_packet("");	// Not supported
474	
475	                    break;
476	
477	                // Single step
478	                case 's':
479	                case 'S':
480	                    dbg_single_step(proc, current_thread);
481	                    last_signals[current_thread] = TRAP_SIGNAL;
482	                    send_formatted_response("S%02x", last_signals[current_thread]);
483	                    break;
484	
485	                // Multi-character command
486	                case 'v':
487	                    if (strcmp(request, "vCont?") == 0)
488	                        send_response_packet("vCont;C;c;S;s");
489	                    else if (memcmp(request, "vCont;", 6) == 0)
490	                    {
491	                        // XXX hack.  There are two things lldb requests.  One is
492	                        // to step one thread while resuming the others.  In this case,
493	                        // I cheat and only step the one.  The other is just to continue,
494	                        // which I perform in the else clause.
495	                        const char *sreq = strchr(request, 's');
496	                        if (sreq != NULL)
497	                        {
498	                            // s:0001
499	                            current_thread = (uint32_t) strtoul(sreq + 2, NULL, 16) - 1;
500	                            dbg_single_step(proc, current_thread);
501	                            last_signals[current_thread] = TRAP_SIGNAL;
502	                            send_formatted_response("S%02x", last_signals[current_thread]);
503	                        }
504	                        else
505	                        {
506	                            run_until_interrupt(proc, enable_fb_window);
507	                            last_signals[current_thread] = TRAP_SIGNAL;
508	                            send_formatted_response("S%02x", last_signals[current_thread]);
509	                        }
510	                    }
511	                    else
512	                        send_response_packet("");
513	
514	                    break;
515	
516	                // Clear breakpoint
517	                case 'z':
518	                    if (dbg_clear_breakpoint(proc, (uint32_t) strtoul(request + 3, NULL, 16)) < 0)
519	                        send_response_packet(""); // Error
520	                    else
521	                        send_response_packet("OK");
522	
523	                    break;
524	
525	                // Set breakpoint
526	                case 'Z':
527	                    if (dbg_set_breakpoint(proc, (uint32_t) strtoul(request + 3, NULL, 16)) < 0)
528	                        send_response_packet(""); // Error
529	                    else
530	                        send_response_packet("OK");
531	
532	                    break;
533	
534	                // Get last signal
535	                case '?':
536	                    send_formatted_response("S%02x", last_signals[current_thread]);
537	                    break;
538	
539	                // Unknown, return error
540	                default:
541	                    send_response_packet("");
542	            }
543	        }
544	
545	        close(client_socket);
546	    }
547	}
