114	// Return the index of the next lowest set bit at or below index (with 0
115	// being the least signficant bit). If there is no set bits below the index,
116	// wrap around and search from the the most significand bit position.
117	// The result is undefined if bitmask is 0
118	static inline uint32_t next_set_bit(uint32_t bitmask, uint32_t index)
119	{
